// Расширяем глобальный объект Window, чтобы TypeScript знал о методах,
// которые добавляются в рантайме (например, через скрипт записи видео).
interface Window {
  /**
   * Запускает запись экрана или видео.
   * Добавляется внешним скриптом.
   */
  startRecording?: () => void;
  /**
   * Останавливает запись и возвращает записанное видео.
   * Добавляется внешним скриптом.
   */
  stopRecording?: () => Promise<Blob>;
}
